import{_ as a,o as s,c as n,a2 as t}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Testing","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/clean-architecture/05-testing.md","filePath":"full-stack/arquitectura/clean-architecture/05-testing.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/clean-architecture/05-testing.md"};function o(r,e,p,d,l,c){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h1><p>Una de las grandes ventajas de Clean Architecture es que permite probar reglas importantes sin depender de servidores, bases de datos ni servicios externos.</p><h2 id="piramide-recomendada" tabindex="-1">Piramide recomendada <a class="header-anchor" href="#piramide-recomendada" aria-label="Permalink to &quot;Piramide recomendada&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E2E tests</span></span>
<span class="line"><span>Integration tests</span></span>
<span class="line"><span>Use case tests</span></span>
<span class="line"><span>Domain tests</span></span></code></pre></div><p>Cuanto mas cerca del dominio, mas rapidos y estables deberian ser los tests.</p><h2 id="tests-de-dominio" tabindex="-1">Tests de dominio <a class="header-anchor" href="#tests-de-dominio" aria-label="Permalink to &quot;Tests de dominio&quot;">​</a></h2><p>Prueban reglas puras.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>given order without lines</span></span>
<span class="line"><span>when confirm</span></span>
<span class="line"><span>then error: order cannot be confirmed</span></span></code></pre></div><p>No necesitan mocks complejos, base de datos ni servidor web.</p><h2 id="tests-de-casos-de-uso" tabindex="-1">Tests de casos de uso <a class="header-anchor" href="#tests-de-casos-de-uso" aria-label="Permalink to &quot;Tests de casos de uso&quot;">​</a></h2><p>Prueban la coordinacion.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>given existing cart</span></span>
<span class="line"><span>and valid payment</span></span>
<span class="line"><span>when checkout</span></span>
<span class="line"><span>then order is created</span></span>
<span class="line"><span>and payment is captured</span></span>
<span class="line"><span>and event is published</span></span></code></pre></div><p>Aqui se pueden usar dobles de prueba para repositorios, gateways y event bus.</p><h2 id="tests-de-infraestructura" tabindex="-1">Tests de infraestructura <a class="header-anchor" href="#tests-de-infraestructura" aria-label="Permalink to &quot;Tests de infraestructura&quot;">​</a></h2><p>Prueban adaptadores concretos:</p><ul><li>Repositorios contra base de datos real o contenedor.</li><li>Clientes HTTP contra servidor fake.</li><li>Serializadores y mappers.</li><li>Consumers de eventos.</li></ul><p>Estos tests son mas lentos, pero dan confianza en la integracion.</p><h2 id="tests-end-to-end" tabindex="-1">Tests end to end <a class="header-anchor" href="#tests-end-to-end" aria-label="Permalink to &quot;Tests end to end&quot;">​</a></h2><p>Prueban el sistema desde fuera:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /orders</span></span>
<span class="line"><span>GET /orders/{id}</span></span></code></pre></div><p>No deben cubrir cada combinacion interna. Su funcion es confirmar que las piezas principales encajan.</p><h2 id="estrategia-de-mocks" tabindex="-1">Estrategia de mocks <a class="header-anchor" href="#estrategia-de-mocks" aria-label="Permalink to &quot;Estrategia de mocks&quot;">​</a></h2><p>Usa mocks para dependencias externas, no para el dominio.</p><p>Buena senal:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FakePaymentGateway</span></span>
<span class="line"><span>InMemoryOrderRepository</span></span></code></pre></div><p>Mala senal:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MockOrder</span></span>
<span class="line"><span>MockOrderLine</span></span>
<span class="line"><span>MockDomainRule</span></span></code></pre></div><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Las reglas de dominio tienen tests rapidos.</li><li>Los casos de uso se prueban sin HTTP.</li><li>Los adaptadores tienen tests de integracion.</li><li>Los tests E2E cubren flujos criticos.</li><li>Los errores de negocio se prueban explicitamente.</li></ul>`,29)])])}const m=a(i,[["render",o]]);export{h as __pageData,m as default};
